async fn chat(State(state): State<Arc<AppState>>, Json(request): Json<ChatRequest>) -> Response {
    // Get or create session
    let session_id = match get_or_create_session(&state, request.session_id).await {
        Ok(id) => id,
        Err(e) => return e.into_response(),
    };

    // Acquire in-process turn gate (waits for other turns to finish)
    let _gate_permit = state.turn_gate.acquire().await;

    // Acquire cross-process workspace lock (blocking, so use spawn_blocking)
    let ws_lock_path = state.workspace_lock.clone();
    let ws_guard = match tokio::task::spawn_blocking(move || ws_lock_path.acquire()).await {
        Ok(Ok(guard)) => guard,
        Ok(Err(e)) => {
            return AppError(
                StatusCode::INTERNAL_SERVER_ERROR,
                format!("Failed to acquire workspace lock: {}", e),
            ).into_response();
        }
        Err(e) => {
            return AppError(
                StatusCode::INTERNAL_SERVER_ERROR,
                format!("Lock task error: {}", e),
            ).into_response();
        }
    };

async fn build_memory_context(&self) -> Result<String> {
    let mut context = String::new();
    let use_delimiters = self.app_config.tools.use_content_delimiters;

    // Show welcome message on brand new workspace (first run)
    if self.memory.is_brand_new() {
        context.push_str(FIRST_RUN_WELCOME);
        context.push_str("\n\n---\n\n");
    }

    // Load IDENTITY.md first (OpenClaw-compatible: agent identity context)
    if let Ok(identity_content) = self.memory.read_identity_file()
        && !identity_content.is_empty()
    {
        if use_delimiters {
            context.push_str(&sanitize::wrap_memory_content(
                "IDENTITY.md", &identity_content, sanitize::MemorySource::Identity,
            ));
        } else {
            context.push_str("# Identity (IDENTITY.md)\n\n");
            context.push_str(&identity_content);
        }
        context.push_str("\n\n---\n\n");
    }

/// A chunk of memory content returned from search
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MemoryChunk {
    pub file: String,
    pub line_start: i32,
    pub line_end: i32,
    pub content: String,
    pub score: f64,
    #[serde(default)]
    pub updated_at: i64,
}

impl MemoryChunk {
    /// Apply temporal decay to the score based on age.
    /// decay_factor = exp(-lambda * age_days)
    pub fn apply_temporal_decay(&mut self, lambda: f64, now_unix: i64) -> f64 {
        if lambda <= 0.0 || self.updated_at <= 0 {
            return self.score;
        }
        let age_secs = (now_unix - self.updated_at).max(0) as f64;
        let age_days = age_secs / (24.0 * 60.0 * 60.0);
        let decay_factor = (-lambda * age_days).exp();
        self.score *= decay_factor;
        self.score
    }
}

