pub trait LLMProvider: Send + Sync {
    fn name(&self) -> String;

    async fn chat(&self, messages: &[Message], tools: Option<&[ToolSchema]>)
    -> Result<LLMResponse>;

    async fn summarize(&self, text: &str) -> Result<String>;

    fn supports_native_search(&self) -> bool {
        false
    }

    fn native_tool_definitions(&self) -> Vec<Value> {
        Vec::new()
    }

    fn reset_session(&self) {}

    async fn chat_stream(
        &self,
        messages: &[Message],
        tools: Option<&[ToolSchema]>,
    ) -> Result<StreamResult> {
        let resp = self.chat(messages, tools).await?;
        match resp.content {
            LLMResponseContent::Text(text) => Ok(Box::pin(futures::stream::once(async move {
                Ok(StreamChunk { delta: text, done: true, tool_calls: None })
            }))),

async fn handle_response(&mut self, response: LLMResponse) -> Result<String> {
    self.add_usage(response.usage);

    match response.content {
        LLMResponseContent::Text(text) => Ok(text),
        LLMResponseContent::ToolCalls { calls, text } => {
            let mut results = Vec::new();

            for call in &calls {
                // Check for stuck loop before executing
                self.loop_detector.record(&call.name, &call.arguments);
                if self.loop_detector.is_stuck() {
                    let tool_name = self.loop_detector.last_tool_name().unwrap_or("unknown");
                    tracing::warn!(
                        "Stuck loop detected: {} called {} times with same args",
                        tool_name, self.loop_detector.max_repeats
                    );
                    let stuck_msg = format!(
                        "SYSTEM: You have called '{}' {} times with the same arguments. \
                         This appears to be a loop. Please try a different approach.",
                        tool_name, self.loop_detector.max_repeats
                    );
                    self.loop_detector.reset();
                    return Ok(stuck_msg);
                }

fn should_compact(&self) -> bool {
    self.session.token_count()
        > (self.config.context_window - self.config.reserve_tokens - SECURITY_BLOCK_RESERVE)
}

fn should_memory_flush(&self) -> bool {
    let hard_limit =
        self.config.context_window - self.config.reserve_tokens - SECURITY_BLOCK_RESERVE;
    let soft_limit = hard_limit.saturating_sub(MEMORY_FLUSH_SOFT_THRESHOLD);
    self.session.token_count() > soft_limit && self.session.should_memory_flush()
}

pub async fn compact_session(&mut self) -> Result<(usize, usize)> {
    let tokens_before = self.session.token_count();
    if self.session.should_memory_flush() {
        self.memory_flush().await?;
    }
    self.session.compact(&*self.provider).await?;

    if !self.app_config.agent.post_compaction_sections.is_empty()
        && let Some(context) = compaction::build_post_compaction_context(
            &self.app_config.workspace_path(),
            &self.app_config.agent.post_compaction_sections,
        )
    {
        self.session.add_message(Message {
            role: Role::System,
            content: context,
            tool_calls: None,
            tool_call_id: None,
            images: Vec::new(),
        });
    }

pub fn messages_for_llm(&self) -> Vec<Message> {
    let mut messages = Vec::new();

    if let Some(ref context) = self.system_context {
        messages.push(Message {
            role: Role::System,
            content: context.clone(),
            tool_calls: None,
            tool_call_id: None,
            images: Vec::new(),
        });
    }

    messages.extend(self.messages.iter().map(|sm| sm.message.clone()));
    messages
}

/// Save session in Pi-compatible JSONL format
pub fn save(&self) -> Result<PathBuf> {
    let dir = get_sessions_dir()?;
    fs::create_dir_all(&dir)?;
    let path = dir.join(format!("{}.jsonl", self.id));
    self.save_to_path(&path)?;
    Ok(path)
}
